"use client"

import React from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { LayoutDashboard, Award, PieChart, History, User } from 'lucide-react';
import { cn } from '@/lib/utils';

/**
 * @fileOverview شريط التنقل السفلي للهواتف لضمان سهولة الانتقال بين الصفحات.
 */

const NAV_ITEMS = [
  { href: '/dashboard', icon: LayoutDashboard, label: 'AI Pulse' },
  { href: '/manual-analysis', icon: Award, label: 'Hassan Pro' },
  { href: '/analysis', icon: PieChart, label: 'Tech Hub' },
  { href: '/history', icon: History, label: 'Log' },
  { href: '/profile', icon: User, label: 'Profile' },
];

export const MobileNav = () => {
  const pathname = usePathname();

  return (
    <div className="lg:hidden fixed bottom-0 left-0 right-0 z-[100] bg-background/80 backdrop-blur-xl border-t border-border flex items-center justify-around h-16 px-2 pb-safe">
      {NAV_ITEMS.map((item) => {
        const Icon = item.icon;
        const isActive = pathname === item.href;
        
        return (
          <Link 
            key={item.href} 
            href={item.href}
            className={cn(
              "flex flex-col items-center justify-center flex-1 h-full gap-1 transition-all",
              isActive ? "text-primary" : "text-muted-foreground"
            )}
          >
            <div className={cn(
              "p-1.5 rounded-lg transition-all",
              isActive && "bg-primary/10"
            )}>
              <Icon className={cn("h-5 w-5", isActive && "fill-primary/20")} />
            </div>
            <span className="text-[8px] font-black uppercase tracking-widest">{item.label}</span>
          </Link>
        );
      })}
    </div>
  );
};